import{_ as l,o as i,c as e,ai as a}from"./chunks/framework.ampVZV4B.js";const c=JSON.parse('{"title":"开发工具","description":"","frontmatter":{},"headers":[],"relativePath":"open-source/dev-tools.md","filePath":"open-source/dev-tools.md"}'),r={name:"open-source/dev-tools.md"};function o(n,t,h,s,u,b){return i(),e("div",null,[...t[0]||(t[0]=[a('<h1 id="开发工具" tabindex="-1">开发工具 <a class="header-anchor" href="#开发工具" aria-label="Permalink to “开发工具”">​</a></h1><p>本页面精选了开发过程中常用的开源工具，包括IDE插件、代码质量工具、调试工具等。</p><h2 id="ide-与编辑器" tabindex="-1">IDE 与编辑器 <a class="header-anchor" href="#ide-与编辑器" aria-label="Permalink to “IDE 与编辑器”">​</a></h2><h3 id="visual-studio-code" tabindex="-1">Visual Studio Code <a class="header-anchor" href="#visual-studio-code" aria-label="Permalink to “Visual Studio Code”">​</a></h3><ul><li><p><strong>VS Code</strong>：微软开源代码编辑器</p><ul><li>GitHub: <a href="https://github.com/microsoft/vscode" target="_blank" rel="noreferrer">https://github.com/microsoft/vscode</a></li><li>特点: 轻量级、插件丰富、跨平台</li></ul></li><li><p><strong>VS Code Extensions</strong>：插件生态</p><ul><li>推荐: Python、Java、Vue、React插件</li></ul></li></ul><h3 id="intellij-idea-社区版" tabindex="-1">IntelliJ IDEA 社区版 <a class="header-anchor" href="#intellij-idea-社区版" aria-label="Permalink to “IntelliJ IDEA 社区版”">​</a></h3><ul><li><strong>IntelliJ IDEA Community</strong>：JetBrains Java IDE <ul><li>GitHub: <a href="https://github.com/JetBrains/intellij-community" target="_blank" rel="noreferrer">https://github.com/JetBrains/intellij-community</a></li><li>功能: Java开发、插件支持</li></ul></li></ul><h3 id="pycharm-社区版" tabindex="-1">PyCharm 社区版 <a class="header-anchor" href="#pycharm-社区版" aria-label="Permalink to “PyCharm 社区版”">​</a></h3><ul><li><strong>PyCharm Community</strong>：JetBrains Python IDE <ul><li>GitHub: <a href="https://github.com/JetBrains/pycharm-community" target="_blank" rel="noreferrer">https://github.com/JetBrains/pycharm-community</a></li><li>功能: Python开发、科学计算</li></ul></li></ul><h2 id="代码质量工具" tabindex="-1">代码质量工具 <a class="header-anchor" href="#代码质量工具" aria-label="Permalink to “代码质量工具”">​</a></h2><h3 id="代码检查" tabindex="-1">代码检查 <a class="header-anchor" href="#代码检查" aria-label="Permalink to “代码检查”">​</a></h3><ul><li><p><strong>ESLint</strong>：JavaScript代码检查</p><ul><li>GitHub: <a href="https://github.com/eslint/eslint" target="_blank" rel="noreferrer">https://github.com/eslint/eslint</a></li><li>功能: 代码规范、错误检测</li></ul></li><li><p><strong>Prettier</strong>：代码格式化</p><ul><li>GitHub: <a href="https://github.com/prettier/prettier" target="_blank" rel="noreferrer">https://github.com/prettier/prettier</a></li><li>功能: 自动格式化、多语言支持</li></ul></li><li><p><strong>Black</strong>：Python代码格式化</p><ul><li>GitHub: <a href="https://github.com/psf/black" target="_blank" rel="noreferrer">https://github.com/psf/black</a></li><li>特点: 无配置、严格格式</li></ul></li></ul><h3 id="静态分析" tabindex="-1">静态分析 <a class="header-anchor" href="#静态分析" aria-label="Permalink to “静态分析”">​</a></h3><ul><li><p><strong>SonarQube</strong>：代码质量检测</p><ul><li>GitHub: <a href="https://github.com/SonarSource/sonarqube" target="_blank" rel="noreferrer">https://github.com/SonarSource/sonarqube</a></li><li>功能: 漏洞检测、代码异味</li></ul></li><li><p><strong>SpotBugs</strong>：Java静态分析</p><ul><li>GitHub: <a href="https://github.com/spotbugs/spotbugs" target="_blank" rel="noreferrer">https://github.com/spotbugs/spotbugs</a></li><li>功能: 缺陷检测</li></ul></li></ul><h2 id="版本控制工具" tabindex="-1">版本控制工具 <a class="header-anchor" href="#版本控制工具" aria-label="Permalink to “版本控制工具”">​</a></h2><h3 id="git-增强工具" tabindex="-1">Git 增强工具 <a class="header-anchor" href="#git-增强工具" aria-label="Permalink to “Git 增强工具”">​</a></h3><ul><li><p><strong>Git LFS</strong>：大文件存储</p><ul><li>GitHub: <a href="https://github.com/git-lfs/git-lfs" target="_blank" rel="noreferrer">https://github.com/git-lfs/git-lfs</a></li><li>功能: 大文件版本控制</li></ul></li><li><p><strong>GitHub CLI</strong>：命令行GitHub工具</p><ul><li>GitHub: <a href="https://github.com/cli/cli" target="_blank" rel="noreferrer">https://github.com/cli/cli</a></li><li>功能: PR管理、Issue处理</li></ul></li></ul><h3 id="git-工作流" tabindex="-1">Git 工作流 <a class="header-anchor" href="#git-工作流" aria-label="Permalink to “Git 工作流”">​</a></h3><ul><li><p><strong>Git Flow</strong>：分支管理模型</p><ul><li>GitHub: <a href="https://github.com/nvie/gitflow" target="_blank" rel="noreferrer">https://github.com/nvie/gitflow</a></li><li>功能: 标准化分支策略</li></ul></li><li><p><strong>Conventional Commits</strong>：提交信息规范</p><ul><li>GitHub: <a href="https://github.com/conventional-changelog/conventional-changelog" target="_blank" rel="noreferrer">https://github.com/conventional-changelog/conventional-changelog</a></li><li>功能: 标准化提交格式</li></ul></li></ul><h2 id="api-开发工具" tabindex="-1">API 开发工具 <a class="header-anchor" href="#api-开发工具" aria-label="Permalink to “API 开发工具”">​</a></h2><h3 id="api-文档" tabindex="-1">API 文档 <a class="header-anchor" href="#api-文档" aria-label="Permalink to “API 文档”">​</a></h3><ul><li><p><strong>Swagger/OpenAPI</strong>：API规范</p><ul><li>GitHub: <a href="https://github.com/swagger-api/swagger-ui" target="_blank" rel="noreferrer">https://github.com/swagger-api/swagger-ui</a></li><li>功能: API文档生成</li></ul></li><li><p><strong>Postman</strong>：API测试工具</p><ul><li>功能: 接口测试、自动化测试</li></ul></li></ul><h3 id="api-客户端" tabindex="-1">API 客户端 <a class="header-anchor" href="#api-客户端" aria-label="Permalink to “API 客户端”">​</a></h3><ul><li><p><strong>Insomnia</strong>：REST客户端</p><ul><li>GitHub: <a href="https://github.com/Kong/insomnia" target="_blank" rel="noreferrer">https://github.com/Kong/insomnia</a></li><li>功能: API设计、测试</li></ul></li><li><p><strong>HTTPie</strong>：命令行HTTP客户端</p><ul><li>GitHub: <a href="https://github.com/httpie/httpie" target="_blank" rel="noreferrer">https://github.com/httpie/httpie</a></li><li>特点: 直观语法、彩色输出</li></ul></li></ul><h2 id="数据库工具" tabindex="-1">数据库工具 <a class="header-anchor" href="#数据库工具" aria-label="Permalink to “数据库工具”">​</a></h2><h3 id="通用工具" tabindex="-1">通用工具 <a class="header-anchor" href="#通用工具" aria-label="Permalink to “通用工具”">​</a></h3><ul><li><p><strong>DBeaver</strong>：通用数据库客户端</p><ul><li>GitHub: <a href="https://github.com/dbeaver/dbeaver" target="_blank" rel="noreferrer">https://github.com/dbeaver/dbeaver</a></li><li>支持: MySQL、PostgreSQL、Redis等</li></ul></li><li><p><strong>TablePlus</strong>：现代化数据库客户端</p><ul><li>功能: 多数据库支持、美观界面</li></ul></li></ul><h3 id="迁移工具" tabindex="-1">迁移工具 <a class="header-anchor" href="#迁移工具" aria-label="Permalink to “迁移工具”">​</a></h3><ul><li><p><strong>Flyway</strong>：数据库版本控制</p><ul><li>GitHub: <a href="https://github.com/flyway/flyway" target="_blank" rel="noreferrer">https://github.com/flyway/flyway</a></li><li>功能: 数据库迁移</li></ul></li><li><p><strong>Liquibase</strong>：数据库重构</p><ul><li>GitHub: <a href="https://github.com/liquibase/liquibase" target="_blank" rel="noreferrer">https://github.com/liquibase/liquibase</a></li><li>功能: 变更管理</li></ul></li></ul><h2 id="容器化工具" tabindex="-1">容器化工具 <a class="header-anchor" href="#容器化工具" aria-label="Permalink to “容器化工具”">​</a></h2><h3 id="docker-工具" tabindex="-1">Docker 工具 <a class="header-anchor" href="#docker-工具" aria-label="Permalink to “Docker 工具”">​</a></h3><ul><li><p><strong>Docker Compose</strong>：多容器应用</p><ul><li>GitHub: <a href="https://github.com/docker/compose" target="_blank" rel="noreferrer">https://github.com/docker/compose</a></li><li>功能: 容器编排</li></ul></li><li><p><strong>Portainer</strong>：Docker可视化管理</p><ul><li>GitHub: <a href="https://github.com/portainer/portainer" target="_blank" rel="noreferrer">https://github.com/portainer/portainer</a></li><li>功能: Web界面管理</li></ul></li></ul><h3 id="kubernetes-工具" tabindex="-1">Kubernetes 工具 <a class="header-anchor" href="#kubernetes-工具" aria-label="Permalink to “Kubernetes 工具”">​</a></h3><ul><li><p><strong>kubectl</strong>：Kubernetes命令行</p><ul><li>GitHub: <a href="https://github.com/kubernetes/kubectl" target="_blank" rel="noreferrer">https://github.com/kubernetes/kubectl</a></li><li>功能: 集群管理</li></ul></li><li><p><strong>Lens</strong>：Kubernetes IDE</p><ul><li>GitHub: <a href="https://github.com/lensapp/lens" target="_blank" rel="noreferrer">https://github.com/lensapp/lens</a></li><li>功能: 可视化管理</li></ul></li><li><p><strong>k9s</strong>：终端Kubernetes管理</p><ul><li>GitHub: <a href="https://github.com/derailed/k9s" target="_blank" rel="noreferrer">https://github.com/derailed/k9s</a></li><li>特点: 键盘操作、实时监控</li></ul></li></ul><h2 id="监控与日志" tabindex="-1">监控与日志 <a class="header-anchor" href="#监控与日志" aria-label="Permalink to “监控与日志”">​</a></h2><h3 id="应用监控" tabindex="-1">应用监控 <a class="header-anchor" href="#应用监控" aria-label="Permalink to “应用监控”">​</a></h3><ul><li><p><strong>Prometheus</strong>：监控系统</p><ul><li>GitHub: <a href="https://github.com/prometheus/prometheus" target="_blank" rel="noreferrer">https://github.com/prometheus/prometheus</a></li><li>功能: 指标收集、告警</li></ul></li><li><p><strong>Grafana</strong>：可视化仪表板</p><ul><li>GitHub: <a href="https://github.com/grafana/grafana" target="_blank" rel="noreferrer">https://github.com/grafana/grafana</a></li><li>功能: 数据可视化</li></ul></li></ul><h3 id="日志工具" tabindex="-1">日志工具 <a class="header-anchor" href="#日志工具" aria-label="Permalink to “日志工具”">​</a></h3><ul><li><p><strong>ELK Stack</strong>：日志分析平台</p><ul><li>Elasticsearch: <a href="https://github.com/elastic/elasticsearch" target="_blank" rel="noreferrer">https://github.com/elastic/elasticsearch</a></li><li>Logstash: <a href="https://github.com/elastic/logstash" target="_blank" rel="noreferrer">https://github.com/elastic/logstash</a></li><li>Kibana: <a href="https://github.com/elastic/kibana" target="_blank" rel="noreferrer">https://github.com/elastic/kibana</a></li></ul></li><li><p><strong>Fluentd</strong>：日志收集器</p><ul><li>GitHub: <a href="https://github.com/fluent/fluentd" target="_blank" rel="noreferrer">https://github.com/fluent/fluentd</a></li><li>功能: 统一日志处理</li></ul></li></ul><h2 id="性能测试工具" tabindex="-1">性能测试工具 <a class="header-anchor" href="#性能测试工具" aria-label="Permalink to “性能测试工具”">​</a></h2><ul><li><p><strong>JMeter</strong>：Apache性能测试</p><ul><li>GitHub: <a href="https://github.com/apache/jmeter" target="_blank" rel="noreferrer">https://github.com/apache/jmeter</a></li><li>功能: 负载测试、压力测试</li></ul></li><li><p><strong>Locust</strong>：Python性能测试</p><ul><li>GitHub: <a href="https://github.com/locustio/locust" target="_blank" rel="noreferrer">https://github.com/locustio/locust</a></li><li>功能: 分布式测试、Web界面</li></ul></li><li><p><strong>k6</strong>：现代性能测试</p><ul><li>GitHub: <a href="https://github.com/grafana/k6" target="_blank" rel="noreferrer">https://github.com/grafana/k6</a></li><li>功能: 脚本化测试、云原生</li></ul></li></ul><h2 id="安全工具" tabindex="-1">安全工具 <a class="header-anchor" href="#安全工具" aria-label="Permalink to “安全工具”">​</a></h2><h3 id="代码安全" tabindex="-1">代码安全 <a class="header-anchor" href="#代码安全" aria-label="Permalink to “代码安全”">​</a></h3><ul><li><p><strong>OWASP ZAP</strong>：Web应用安全扫描</p><ul><li>GitHub: <a href="https://github.com/zaproxy/zaproxy" target="_blank" rel="noreferrer">https://github.com/zaproxy/zaproxy</a></li><li>功能: 漏洞扫描</li></ul></li><li><p><strong>SonarQube</strong>：代码质量与安全</p><ul><li>GitHub: <a href="https://github.com/SonarSource/sonarqube" target="_blank" rel="noreferrer">https://github.com/SonarSource/sonarqube</a></li><li>功能: 安全漏洞检测</li></ul></li></ul><h3 id="依赖检查" tabindex="-1">依赖检查 <a class="header-anchor" href="#依赖检查" aria-label="Permalink to “依赖检查”">​</a></h3><ul><li><p><strong>OWASP Dependency-Check</strong>：依赖漏洞扫描</p><ul><li>GitHub: <a href="https://github.com/jeremylong/DependencyCheck" target="_blank" rel="noreferrer">https://github.com/jeremylong/DependencyCheck</a></li><li>功能: 第三方库漏洞检测</li></ul></li><li><p><strong>Snyk</strong>：开发安全平台</p><ul><li>功能: 依赖扫描、容器安全</li></ul></li></ul><h2 id="ci-cd-工具" tabindex="-1">CI/CD 工具 <a class="header-anchor" href="#ci-cd-工具" aria-label="Permalink to “CI/CD 工具”">​</a></h2><h3 id="jenkins" tabindex="-1">Jenkins <a class="header-anchor" href="#jenkins" aria-label="Permalink to “Jenkins”">​</a></h3><ul><li><strong>Jenkins</strong>：自动化服务器 <ul><li>GitHub: <a href="https://github.com/jenkinsci/jenkins" target="_blank" rel="noreferrer">https://github.com/jenkinsci/jenkins</a></li><li>功能: 持续集成、持续部署</li></ul></li></ul><h3 id="github-actions" tabindex="-1">GitHub Actions <a class="header-anchor" href="#github-actions" aria-label="Permalink to “GitHub Actions”">​</a></h3><ul><li><strong>GitHub Actions</strong>：工作流自动化 <ul><li>GitHub: <a href="https://github.com/actions" target="_blank" rel="noreferrer">https://github.com/actions</a></li><li>功能: CI/CD、自动化任务</li></ul></li></ul><h3 id="gitlab-ci" tabindex="-1">GitLab CI <a class="header-anchor" href="#gitlab-ci" aria-label="Permalink to “GitLab CI”">​</a></h3><ul><li><strong>GitLab Runner</strong>：GitLab CI执行器 <ul><li>GitHub: <a href="https://github.com/gitlabhq/gitlab-runner" target="_blank" rel="noreferrer">https://github.com/gitlabhq/gitlab-runner</a></li><li>功能: 作业执行</li></ul></li></ul><h2 id="文档工具" tabindex="-1">文档工具 <a class="header-anchor" href="#文档工具" aria-label="Permalink to “文档工具”">​</a></h2><ul><li><p><strong>MkDocs</strong>：静态站点生成器</p><ul><li>GitHub: <a href="https://github.com/mkdocs/mkdocs" target="_blank" rel="noreferrer">https://github.com/mkdocs/mkdocs</a></li><li>功能: Markdown文档</li></ul></li><li><p><strong>Docusaurus</strong>：React文档框架</p><ul><li>GitHub: <a href="https://github.com/facebook/docusaurus" target="_blank" rel="noreferrer">https://github.com/facebook/docusaurus</a></li><li>功能: 现代化文档站点</li></ul></li><li><p><strong>Sphinx</strong>：Python文档生成器</p><ul><li>GitHub: <a href="https://github.com/sphinx-doc/sphinx" target="_blank" rel="noreferrer">https://github.com/sphinx-doc/sphinx</a></li><li>功能: API文档、书籍</li></ul></li></ul><h2 id="调试工具" tabindex="-1">调试工具 <a class="header-anchor" href="#调试工具" aria-label="Permalink to “调试工具”">​</a></h2><h3 id="网络调试" tabindex="-1">网络调试 <a class="header-anchor" href="#网络调试" aria-label="Permalink to “网络调试”">​</a></h3><ul><li><p><strong>Wireshark</strong>：网络协议分析器</p><ul><li>GitHub: <a href="https://github.com/wireshark/wireshark" target="_blank" rel="noreferrer">https://github.com/wireshark/wireshark</a></li><li>功能: 网络包分析</li></ul></li><li><p><strong>Charles</strong>：Web调试代理</p><ul><li>功能: HTTP/HTTPS代理、移动端调试</li></ul></li></ul><h3 id="内存调试" tabindex="-1">内存调试 <a class="header-anchor" href="#内存调试" aria-label="Permalink to “内存调试”">​</a></h3><ul><li><p><strong>MAT (Memory Analyzer)</strong>：Java堆转储分析</p><ul><li>GitHub: <a href="https://github.com/eclipse/mat" target="_blank" rel="noreferrer">https://github.com/eclipse/mat</a></li><li>功能: 内存泄漏分析</li></ul></li><li><p><strong>Valgrind</strong>：内存调试工具</p><ul><li>GitHub: <a href="https://github.com/valgrind/valgrind" target="_blank" rel="noreferrer">https://github.com/valgrind/valgrind</a></li><li>功能: 内存错误检测</li></ul></li></ul><h2 id="团队协作工具" tabindex="-1">团队协作工具 <a class="header-anchor" href="#团队协作工具" aria-label="Permalink to “团队协作工具”">​</a></h2><ul><li><p><strong>GitLab</strong>：DevOps平台</p><ul><li>GitHub: <a href="https://github.com/gitlabhq/gitlabhq" target="_blank" rel="noreferrer">https://github.com/gitlabhq/gitlabhq</a></li><li>功能: 代码托管、CI/CD</li></ul></li><li><p><strong>Gitea</strong>：轻量级Git服务</p><ul><li>GitHub: <a href="https://github.com/go-gitea/gitea" target="_blank" rel="noreferrer">https://github.com/go-gitea/gitea</a></li><li>特点: 自托管、简单部署</li></ul></li><li><p><strong>Mattermost</strong>：开源Slack替代品</p><ul><li>GitHub: <a href="https://github.com/mattermost/mattermost" target="_blank" rel="noreferrer">https://github.com/mattermost/mattermost</a></li><li>功能: 团队沟通、文件共享</li></ul></li></ul>',62)])])}const p=l(r,[["render",o]]);export{c as __pageData,p as default};
